# NX Open Python - generated by nx-cad skill
# ----------------------------------------------------------------------------
# HOW TO RUN:
#   1. Copy this file and the cadnx/ folder to a machine with Siemens NX installed.
#   2. Open NX -> File -> Execute -> NX Open -> select this file.
#   3. NX builds the geometry and exports the STEP file next to this journal.
# ----------------------------------------------------------------------------

import math
import os
import sys

_SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
for _candidate in (
    _SCRIPT_DIR,
    os.path.abspath(os.path.join(_SCRIPT_DIR, "..", "skills", "nx-cad")),
):
    if _candidate not in sys.path:
        sys.path.insert(0, _candidate)

from cadnx import NXBuilder


def build(output_path: str = None):
    b = NXBuilder()

    # Coordinate convention: X is engine centerline, radial directions are in YZ.
    x_axis = (1.0, 0.0, 0.0)
    neg_x_axis = (-1.0, 0.0, 0.0)

    # Primary frame dimensions, millimeters.
    casing_od = 520.0
    casing_id = 460.0
    casing_length = 86.0
    casing_x_min = -43.0
    casing_x_max = 43.0

    forward_flange_x = -43.0
    forward_flange_od = 570.0
    forward_flange_id = 455.0
    forward_flange_thickness = 14.0
    forward_flange_hole_count = 36
    forward_flange_hole_diameter = 8.5
    forward_flange_bcd = 535.0

    aft_flange_x = 43.0
    aft_flange_od = 560.0
    aft_flange_id = 458.0
    aft_flange_thickness = 14.0
    aft_flange_hole_count = 36
    aft_flange_hole_diameter = 8.5
    aft_flange_bcd = 525.0
    aft_flange_start_angle_degrees = 5.0

    hub_od = 150.0
    hub_bore_diameter = 82.0
    hub_length = 112.0
    hub_x_min = -56.0
    hub_x_max = 56.0
    forward_seat_diameter = 92.0
    forward_seat_depth = 16.0
    aft_seat_diameter = 96.0
    aft_seat_depth = 18.0

    inner_flange_x = 48.0
    inner_flange_od = 190.0
    inner_flange_id = 82.0
    inner_flange_thickness = 12.0
    inner_flange_hole_count = 16
    inner_flange_hole_diameter = 6.5
    inner_flange_bcd = 168.0

    primary_strut_count = 8
    primary_strut_tangential_chord = 58.0
    primary_strut_axial_thickness = 22.0
    secondary_strut_count = 8
    secondary_strut_tangential_width = 34.0
    secondary_strut_axial_thickness = 16.0

    oil_angle_degrees = 22.5
    oil_passage_diameter = 10.0
    oil_boss_diameter = 24.0
    oil_boss_height = 12.0
    instrumentation_angle_degrees = 202.5
    instrumentation_passage_diameter = 6.0
    instrumentation_boss_diameter = 18.0
    instrumentation_boss_height = 8.0

    accessory_angle_degrees = 90.0
    accessory_pad_x = 8.0
    accessory_pad_tangential = 72.0
    accessory_pad_axial = 46.0
    accessory_pad_height = 8.0
    accessory_hole_diameter = 6.0
    accessory_hole_tangential_pitch = 52.0
    accessory_hole_axial_pitch = 28.0

    borescope_angle_degrees = 270.0
    borescope_x = -12.0
    borescope_boss_diameter = 34.0
    borescope_boss_height = 10.0
    borescope_hole_diameter = 12.0

    stiffener_count = 12
    stiffener_start_angle_degrees = 15.0
    stiffener_tangential_width = 24.0
    stiffener_axial_width = 16.0
    stiffener_radial_height = 28.0

    groove_width = 8.0
    groove_depth = 3.0
    groove_x_locations = (-22.0, 22.0)

    feature_overlap = 0.75
    cutter_overlap = 1.0
    through_overcut = 6.0
    chamfer_offset = 0.8

    casing_or = casing_od / 2.0
    casing_ir = casing_id / 2.0
    hub_or = hub_od / 2.0
    forward_flange_or = forward_flange_od / 2.0
    aft_flange_or = aft_flange_od / 2.0
    inner_flange_or = inner_flange_od / 2.0
    strut_radial_length = casing_ir - hub_or + 2.0 * feature_overlap
    strut_radial_center = (casing_ir + hub_or) / 2.0

    b.require_positive(
        casing_length=casing_length,
        casing_wall=(casing_od - casing_id) / 2.0,
        hub_wall=(hub_od - hub_bore_diameter) / 2.0,
        primary_strut_radial_length=strut_radial_length,
    )
    b.require_min_wall(forward_flange_od - forward_flange_id, forward_flange_hole_diameter, 8.0, "forward flange hole lane")
    b.require_min_wall(aft_flange_od - aft_flange_id, aft_flange_hole_diameter, 8.0, "aft flange hole lane")
    b.require_min_wall(inner_flange_od - inner_flange_id, inner_flange_hole_diameter, 8.0, "inner flange hole lane")
    b.require_feature_budget(
        boolean_operations=140,
        micro_holes=99,
        patterned_features=primary_strut_count + secondary_strut_count + 24 + 3,
        max_boolean_operations=190,
        max_micro_holes=130,
        max_patterned_features=140,
    )

    def radial(angle_degrees):
        a = math.radians(angle_degrees)
        return (0.0, math.cos(a), math.sin(a))

    def tangent(angle_degrees):
        a = math.radians(angle_degrees)
        return (0.0, -math.sin(a), math.cos(a))

    def point_at(x, radius, angle_degrees):
        r = radial(angle_degrees)
        return (x, radius * r[1], radius * r[2])

    def unite_annulus(target, outer_diameter, inner_diameter, length, x_start):
        outer = b.cylinder(outer_diameter, length, origin=(x_start, 0.0, 0.0), axis=x_axis)
        bore = b.cylinder(inner_diameter, length + 2.0 * through_overcut, origin=(x_start - through_overcut, 0.0, 0.0), axis=x_axis)
        b.boolean_subtract(outer, bore)
        b.boolean_unite(target, outer)

    frame = b.cylinder(casing_od, casing_length, origin=(casing_x_min, 0.0, 0.0), axis=x_axis)
    casing_bore = b.cylinder(casing_id, casing_length + 2.0 * through_overcut, origin=(casing_x_min - through_overcut, 0.0, 0.0), axis=x_axis)
    b.boolean_subtract(frame, casing_bore)

    unite_annulus(frame, forward_flange_od, forward_flange_id, forward_flange_thickness, forward_flange_x - forward_flange_thickness)
    unite_annulus(frame, aft_flange_od, aft_flange_id, aft_flange_thickness, aft_flange_x)
    unite_annulus(frame, hub_od, hub_bore_diameter, hub_length, hub_x_min)
    unite_annulus(frame, inner_flange_od, inner_flange_id, inner_flange_thickness, inner_flange_x - inner_flange_thickness / 2.0)

    # Bearing seats are represented as coaxial counterbore cuts from each end.
    forward_seat = b.cylinder(forward_seat_diameter, forward_seat_depth + cutter_overlap, origin=(hub_x_min - cutter_overlap, 0.0, 0.0), axis=x_axis)
    b.boolean_subtract(frame, forward_seat)
    aft_seat = b.cylinder(aft_seat_diameter, aft_seat_depth + cutter_overlap, origin=(hub_x_max + cutter_overlap, 0.0, 0.0), axis=neg_x_axis)
    b.boolean_subtract(frame, aft_seat)

    for i in range(primary_strut_count):
        angle = i * 360.0 / primary_strut_count
        r = radial(angle)
        t = tangent(angle)
        center = point_at(0.0, strut_radial_center, angle)
        strut = b.oriented_box(
            strut_radial_length,
            primary_strut_tangential_chord,
            primary_strut_axial_thickness,
            center=center,
            u_axis=r,
            v_axis=t,
            w_axis=x_axis,
        )
        nose = b.cylinder(
            primary_strut_tangential_chord,
            primary_strut_axial_thickness,
            origin=(-primary_strut_axial_thickness / 2.0, center[1], center[2]),
            axis=x_axis,
        )
        b.boolean_unite(strut, nose)
        b.boolean_unite(frame, strut)

    for i in range(secondary_strut_count):
        angle = 22.5 + i * 360.0 / secondary_strut_count
        r = radial(angle)
        t = tangent(angle)
        center = point_at(0.0, strut_radial_center, angle)
        strut = b.oriented_box(
            strut_radial_length,
            secondary_strut_tangential_width,
            secondary_strut_axial_thickness,
            center=center,
            u_axis=r,
            v_axis=t,
            w_axis=x_axis,
        )
        tail = b.cylinder(
            secondary_strut_tangential_width,
            secondary_strut_axial_thickness,
            origin=(-secondary_strut_axial_thickness / 2.0, center[1], center[2]),
            axis=x_axis,
        )
        b.boolean_unite(strut, tail)
        b.boolean_unite(frame, strut)

    def flange_holes(count, diameter, bcd, start_angle_degrees, x_start, direction):
        for i in range(count):
            angle = start_angle_degrees + i * 360.0 / count
            p = point_at(x_start, bcd / 2.0, angle)
            tool = b.cylinder(diameter, forward_flange_thickness + aft_flange_thickness + 2.0 * through_overcut, origin=p, axis=direction)
            b.boolean_subtract(frame, tool)

    flange_holes(forward_flange_hole_count, forward_flange_hole_diameter, forward_flange_bcd, 0.0, forward_flange_x - forward_flange_thickness - through_overcut, x_axis)
    flange_holes(aft_flange_hole_count, aft_flange_hole_diameter, aft_flange_bcd, aft_flange_start_angle_degrees, aft_flange_x + aft_flange_thickness + through_overcut, neg_x_axis)

    for i in range(inner_flange_hole_count):
        angle = i * 360.0 / inner_flange_hole_count
        p = point_at(inner_flange_x - inner_flange_thickness / 2.0 - through_overcut, inner_flange_bcd / 2.0, angle)
        tool = b.cylinder(inner_flange_hole_diameter, inner_flange_thickness + 2.0 * through_overcut, origin=p, axis=x_axis)
        b.boolean_subtract(frame, tool)

    for groove_x in groove_x_locations:
        groove_outer = b.cylinder(casing_od + 20.0, groove_width, origin=(groove_x - groove_width / 2.0, 0.0, 0.0), axis=x_axis)
        groove_inner = b.cylinder(casing_od - 2.0 * groove_depth, groove_width + 2.0 * cutter_overlap, origin=(groove_x - groove_width / 2.0 - cutter_overlap, 0.0, 0.0), axis=x_axis)
        b.boolean_subtract(groove_outer, groove_inner)
        b.boolean_subtract(frame, groove_outer)

    def radial_boss_with_hole(angle, x_center, boss_diameter, boss_height, hole_diameter):
        r = radial(angle)
        outer_start = casing_or - feature_overlap
        boss = b.cylinder(boss_diameter, boss_height + feature_overlap, origin=(x_center, outer_start * r[1], outer_start * r[2]), axis=r)
        b.boolean_unite(frame, boss)
        hole_origin_radius = casing_or + boss_height + through_overcut
        tool = b.cylinder(hole_diameter, casing_od, origin=(x_center, hole_origin_radius * r[1], hole_origin_radius * r[2]), axis=(-r[0], -r[1], -r[2]))
        b.boolean_subtract(frame, tool)

    radial_boss_with_hole(oil_angle_degrees, 0.0, oil_boss_diameter, oil_boss_height, oil_passage_diameter)
    radial_boss_with_hole(instrumentation_angle_degrees, 0.0, instrumentation_boss_diameter, instrumentation_boss_height, instrumentation_passage_diameter)
    radial_boss_with_hole(borescope_angle_degrees, borescope_x, borescope_boss_diameter, borescope_boss_height, borescope_hole_diameter)

    pad_angle = accessory_angle_degrees
    r = radial(pad_angle)
    t = tangent(pad_angle)
    pad_center_radius = casing_or + accessory_pad_height / 2.0 - feature_overlap
    pad = b.oriented_box(
        accessory_pad_tangential,
        accessory_pad_height + feature_overlap,
        accessory_pad_axial,
        center=(accessory_pad_x, pad_center_radius * r[1], pad_center_radius * r[2]),
        u_axis=t,
        v_axis=r,
        w_axis=x_axis,
    )
    b.boolean_unite(frame, pad)
    for sx in (-1.0, 1.0):
        for st in (-1.0, 1.0):
            x = accessory_pad_x + sx * accessory_hole_axial_pitch / 2.0
            tangential_offset = st * accessory_hole_tangential_pitch / 2.0
            y = (casing_or + accessory_pad_height + through_overcut) * r[1] + tangential_offset * t[1]
            z = (casing_or + accessory_pad_height + through_overcut) * r[2] + tangential_offset * t[2]
            tool = b.cylinder(accessory_hole_diameter, casing_od, origin=(x, y, z), axis=(-r[0], -r[1], -r[2]))
            b.boolean_subtract(frame, tool)

    for i in range(stiffener_count):
        angle = stiffener_start_angle_degrees + i * 360.0 / stiffener_count
        r = radial(angle)
        t = tangent(angle)
        for x_center in (forward_flange_x - forward_flange_thickness / 2.0, aft_flange_x + aft_flange_thickness / 2.0):
            stiffener_radius = casing_or + stiffener_radial_height / 2.0 - feature_overlap
            rib = b.oriented_box(
                stiffener_radial_height + feature_overlap,
                stiffener_tangential_width,
                stiffener_axial_width,
                center=(x_center, stiffener_radius * r[1], stiffener_radius * r[2]),
                u_axis=r,
                v_axis=t,
                w_axis=x_axis,
            )
            b.boolean_unite(frame, rib)

    # Conservative edge breaks on exposed axial faces. Dense root fillets are left to NX-side refinement if needed.
    b.chamfer(b.get_edges_in_box(frame, (hub_x_min - 1.0, -forward_flange_or - 2.0, -forward_flange_or - 2.0), (hub_x_min + 1.0, forward_flange_or + 2.0, forward_flange_or + 2.0)), chamfer_offset)
    b.chamfer(b.get_edges_in_box(frame, (hub_x_max - 1.0, -aft_flange_or - 2.0, -aft_flange_or - 2.0), (hub_x_max + 1.0, aft_flange_or + 2.0, aft_flange_or + 2.0)), chamfer_offset)

    if output_path is None:
        output_path = os.path.splitext(os.path.abspath(__file__))[0] + ".step"
    b.export_step(output_path)


def main():
    default_output = os.path.splitext(os.path.abspath(__file__))[0] + ".step"
    output = sys.argv[1] if len(sys.argv) > 1 else default_output
    build(output)


if __name__ == "__main__":
    main()
